import 'package:flutter/material.dart';
class PiyiAvatar extends StatelessWidget{const PiyiAvatar({super.key,this.imageUrl,this.name,this.size=48,this.icon=Icons.pets});final String? imageUrl;final String? name;final double size;final IconData icon;@override Widget build(BuildContext context){final initial=(name!=null&&name!.isNotEmpty)?name![0].toUpperCase():null;return CircleAvatar(radius:size/2,backgroundImage:imageUrl==null?null:NetworkImage(imageUrl!),child:imageUrl==null?(initial==null?Icon(icon):Text(initial,style:TextStyle(fontSize:size*.38,fontWeight:FontWeight.w900))):null);}}
